import numpy as np

# Constants for the board and pieces
BOARD_SIZE = 8
EMPTY = ' '
WHITE = 'W'
BLACK = 'B'
KING_WHITE = 'WK'
KING_BLACK = 'BK'

# Function to initialize an empty board
def init_board():
    board = np.zeros((BOARD_SIZE, BOARD_SIZE), dtype=str)
    for row in range(0, BOARD_SIZE, 2):
        board[row][1:8:2] = BLACK
        board[row+1][::2] = BLACK
    return board

# Function to print the board
def print_board(board):
    for row in board:
        print(' '.join(row))
    print()

# Function to move a piece on the board
def move_piece(board, start_row, start_col, end_row, end_col):
    piece = board[start_row][start_col]
    board[start_row][start_col] = EMPTY
    board[end_row][end_col] = piece
    if (end_row == 0 and piece == BLACK) or (end_row == BOARD_SIZE - 1 and piece == WHITE):
        board[end_row][end_col] = KING_WHITE if piece == WHITE else KING_BLACK
    return board

# Function to check if a move is valid
def is_valid_move(board, start_row, start_col, end_row, end_col, player):
    piece = board[start_row][start_col]
    direction = 1 if player == BLACK else -1
    if end_row < 0 or end_row >= BOARD_SIZE or end_col < 0 or end_col >= BOARD_SIZE:
        return False
    if board[end_row][end_col] != EMPTY:
        return False
    if start_row == end_row and start_col == end_col:
        return False
    if abs(end_row - start_row) != abs(end_col - start_col):
        return False
    if player == BLACK and start_row > end_row or player == WHITE and start_row < end_row:
        return False
    # Check for diagonal capture
    if abs(end_row - start_row) == 2 and abs(end_col - start_col) == 2:
        captured_piece = board[(start_row + end_row) // 2][(start_col + end_col) // 2]
        if (player == BLACK and captured_piece != WHITE and captured_piece != KING_WHITE) or (player == WHITE and captured_piece != BLACK and captured_piece != KING_BLACK):
            return False
    return True

# Function to get all valid moves for a player
def get_valid_moves(board, player):
    moves = []
    for row in range(BOARD_SIZE):
        for col in range(BOARD_SIZE):
            if board[row][col] == (player + 'K') or board[row][col] == player:
                moves.append((row, col))
    return moves

